const { Manifold, label, setCircularSegments } = api;
setCircularSegments(32);

function box(min, max) {
  const s = [max[0] - min[0], max[1] - min[1], max[2] - min[2]];
  const c = [(min[0] + max[0]) / 2, (min[1] + max[1]) / 2, (min[2] + max[2]) / 2];
  return Manifold.cube(s, true).translate(c);
}

// Shell: 24w x 15h x 4d, centered at origin, front face at y=-2
const shell = box([-12, -2, -7.5], [12, 2, 7.5]);

// Reel windows: two circular recesses on the front face
// Each reel: cylinder recessed into front face
const reelRadius = 2.8;
const reelDepth = 1.2;
const reelLX = -5;
const reelRX = 5;
const reelZ = 0.5;

// Outer dark reel rings (cylinders slightly proud)
const reelL = Manifold.cylinder(reelDepth, reelRadius, reelRadius, 32).rotate([90, 0, 0]).translate([reelLX, -2.1, reelZ]);
const reelR = Manifold.cylinder(reelDepth, reelRadius, reelRadius, 32).rotate([90, 0, 0]).translate([reelRX, -2.1, reelZ]);

// Hub cylinders at center of each reel (lighter)
const hubRadius = 1.2;
const hubL = Manifold.cylinder(reelDepth + 0.2, hubRadius, hubRadius, 32).rotate([90, 0, 0]).translate([reelLX, -2.2, reelZ]);
const hubR = Manifold.cylinder(reelDepth + 0.2, hubRadius, hubRadius, 32).rotate([90, 0, 0]).translate([reelRX, -2.2, reelZ]);

// Label strip across upper front: from x=-10 to x=10, z=2 to 7, y front
const labelStrip = box([-10, -2.1, 1.5], [10, -1.8, 7.0]);

// Tape window cutout (below center between reels) — a slot shape
const tapeWindow = box([-3.5, -2.2, -2.5], [3.5, -1.7, -0.5]);

// Small guide holes row along bottom edge
const hole1 = Manifold.cylinder(0.4, 0.5, 0.5, 16).rotate([90, 0, 0]).translate([-4, -2.2, -6]);
const hole2 = Manifold.cylinder(0.4, 0.5, 0.5, 16).rotate([90, 0, 0]).translate([0, -2.2, -6]);
const hole3 = Manifold.cylinder(0.4, 0.5, 0.5, 16).rotate([90, 0, 0]).translate([4, -2.2, -6]);

// Assemble: subtract tape window and holes from shell, then add features
const bodyBase = shell.subtract(tapeWindow).subtract(hole1).subtract(hole2).subtract(hole3);

return label(bodyBase, 'shell')
  .add(label(reelL.add(reelR), 'reels'))
  .add(label(hubL.add(hubR), 'hubs'))
  .add(label(labelStrip, 'label'));
